import { Component, Event, EventEmitter, h, Host, Method, Prop, State, Watch } from '@stencil/core';
import isEqual from 'lodash.isequal';
import { TreeMenuItem } from '@src/mx-components/menu-item/mx-menu-item/menu-item.interface';
import cloneDeep from 'lodash/cloneDeep';
import { findRootParent } from '@src/mx-components/menu-item/mx-menu-item/menu-item-utils';
import { copyAllUUIDsToNewArray, setNewUuidsForNestedItems } from '@src/utils/mx-utils/item-uuids';
import { isNullOrUndefined, isNullOrUndefinedOrEmptyString, removeCircularReplacer } from '@src/utils/mx-utils/utils';

@Component({
  tag: 'mx-pick-list',
  styleUrl: 'mx-pick-list.css'
})
export class MxPickList {
  /** Sets the items on the source list.
   * This prop can be used to setup tree like list in the pick list. */
  @Prop({ mutable: true }) items: TreeMenuItem[] = [];

  @Watch('items')
  handleItemsChange(newValue: TreeMenuItem[]) {
    setNewUuidsForNestedItems(newValue, 'children');
    this.setAddButtonStatus(this.items);
  }

  /** Sets the items already selected.
   * This is usually a subset of the items list.
   * This prop also can be used to setup a tree like list. */
  @Prop({ mutable: true }) accumulatedItems: TreeMenuItem[] = [];

  @Watch('accumulatedItems')
  handleAccumulateItemChange(newValue) {
    // Only for freshly passed in values.
    // This will re-update the items selected on the left list.
    if (newValue && newValue[0] && newValue[0].uuid == undefined) {
      // User is trying to reset the selection here. Lets reset the component and reinitialize
      this.items.forEach((it) => this.clearItemSelection(it));
      this.initializeAccumulatedItems();
    }
    this.items = cloneDeep(this.items);
    this.setRemoveButtonStatus(this.accumulatedItems);
  }

  /** Determines the width of the item lists. */
  @Prop() readonly width: number = 680;
  /** Sets the height of the list container. */
  @Prop() readonly height: number = 300;
  /** Sets compact checkboxes. */
  @Prop() readonly isCompact: boolean = false;
  /** Hides Available and Picked count if set to true. */
  @Prop() readonly hideCount: boolean = false;
  /** Shows/hides the child count in the menu-items. */
  @Prop() readonly showChildCount: boolean = false;
  /** Shows/hides carets in the menu-items. */
  @Prop() readonly hideCaret: boolean = false;

  /** Emits event on picklist when the accumulated items are updated. */
  @Event() accumulatedEvent: EventEmitter<string>;
  /** Emits event on picklist when an unexpanded item in the source list is opened.*/
  @Event() sourceOpenEvent: EventEmitter<TreeMenuItem>;
  /** Emits event on picklist when a expanded item in the source list is closed. */
  @Event() sourceCloseEvent: EventEmitter<TreeMenuItem>;
  /** Emits event on picklist when an unexpanded item in the destination list is opened. */
  @Event() destinationOpenEvent: EventEmitter<TreeMenuItem>;
  /** Emits event on picklist when a expanded item in the destination list is closed. */
  @Event() destinationCloseEvent: EventEmitter<TreeMenuItem>;

  @State() addButtonEnabled = false;
  @State() removeButtonEnabled = false;

  private leftContainer: HTMLMxPickListContainerElement;
  private rightContainer: HTMLMxPickListContainerElement;

  /** Method to reset the Pick List. */
  @Method()
  async clearAllSelection() {
    this.addButtonEnabled = false;
    this.removeButtonEnabled = false;
    this.accumulatedItems = [];
    this.items.forEach((it) => this.clearItemSelection(it));
    this.items = [...this.items];
    await this.leftContainer.resetPickListContainer();
    await this.rightContainer.resetPickListContainer();
  }

  constructor() {
    setNewUuidsForNestedItems(this.items, 'children');
  }

  componentWillLoad() {
    this.setUp();
    this.setAddButtonStatus(this.items);
    this.initializeAccumulatedItems();
  }

  private clearItemSelection(item: TreeMenuItem) {
    item.selected = false;
    item.indeterminate = false;
    item.disabled = false;
    item.children?.forEach((it) => {
      this.clearItemSelection(it);
      if (!isNullOrUndefined(it.children)) {
        this.clearItemSelection(it);
      }
    });
  }

  private initializeAccumulatedItems() {
    if (!isNullOrUndefined(this.accumulatedItems)) {
      copyAllUUIDsToNewArray(this.items, this.accumulatedItems, 'children');
      this.disableAccumulatedItemsOnLeftSide();
    }
  }

  private disableAccumulatedItemsOnLeftSide() {
    this.accumulatedItems.forEach((it) => {
      this.items.forEach((item) => {
        if (it.uuid === item.uuid) {
          if (!isNullOrUndefined(it.children)) {
            const selectedChildrenCount = it.children.length;
            const totalChildCount = item.children.length;
            const childrenLengthNotMatch = selectedChildrenCount > 0 && selectedChildrenCount < totalChildCount;
            item.selected = !childrenLengthNotMatch;
            item.indeterminate = childrenLengthNotMatch;
            item.disabled = !childrenLengthNotMatch;
            this.disableAndSelectFoundChildren(it, item);
          } else {
            item.selected = true;
            item.indeterminate = false;
            item.disabled = true;
          }
        }
      });
    });
  }

  private disableAndSelectFoundChildren(item: TreeMenuItem, foundItem: TreeMenuItem) {
    item.children?.forEach((it) => {
      const find = foundItem.children?.find((findItem) => findItem.uuid === it.uuid);
      if (!isNullOrUndefined(find)) {
        if (isNullOrUndefined(it.children)) {
          find.selected = true;
          find.indeterminate = false;
          find.disabled = true;
        } else {
          this.disableAndSelectFoundChildren(it, find);
        }
      }
    });
  }

  private readonly moveLeftToRight = () => {
    this.createAndAddItemsToTheRight(this.items);
    this.disableLeftItems(this.items);
    this.items = cloneDeep(this.items);
    this.accumulatedEvent.emit(removeCircularReplacer(this.accumulatedItems, true));
    this.addButtonEnabled = false;
    this.leftContainer.unselectSelectAll().then(console.debug);
    this.rightContainer.unselectSelectAll().then(console.debug);
    this.setRemoveButtonStatus(this.accumulatedItems);
  };

  private createAndAddItemsToTheRight(items: TreeMenuItem[]) {
    if (isNullOrUndefined(items)) {
      return;
    }
    items.filter((i) => !i.disabled && (i.selected || i.indeterminate)).forEach((it) => {
      const index = this.accumulatedItems.findIndex((i) => i.uuid === it.uuid);
      if (index < 0) {
        const createItem = this.buildNewTreeMenuItemForTheRight(it);
        this.accumulatedItems = [...this.accumulatedItems, createItem];
      } else {
        this.accumulatedItems[index] = this.buildNewTreeMenuItemForTheRight(it, this.accumulatedItems[index]);
        this.accumulatedItems = [...this.accumulatedItems];
      }
    });
  }

  private buildNewTreeMenuItemForTheRight(it: TreeMenuItem, existingItem?: TreeMenuItem) {
    const newTreeMenuItem = {
      label: it.label,
      value: it.value,
      selected: false,
      indeterminate: false,
      hideCheckbox: it.hideCheckbox,
      uuid: it.uuid
    };
    this.buildChildrenForTheRight(it.children, newTreeMenuItem, existingItem);
    return newTreeMenuItem;
  }

  private buildChildrenForTheRight(
    sourceChildren: TreeMenuItem[],
    destParent: TreeMenuItem,
    existingItem?: TreeMenuItem) {
    if (isNullOrUndefined(sourceChildren)) {
      return;
    }
    destParent.children = [];
    const selection = sourceChildren.filter((child) => child.selected || child.indeterminate);
    selection.forEach((child) => {
      let selected = false;
      let indeterminate = false;
      if (!isNullOrUndefined(existingItem)) {
        const findChild = existingItem.children?.find((it) => it.uuid === child.uuid);
        if (!isNullOrUndefined(findChild)) {
          selected = findChild.selected;
          indeterminate = findChild.indeterminate;
        }
      }
      const newTreeMenuItem = {
        label: child.label,
        value: child.value,
        selected,
        indeterminate,
        parent: destParent,
        hideCheckbox: child.hideCheckbox,
        uuid: child.uuid
      };
      destParent.children = [...destParent.children, newTreeMenuItem];
      this.buildChildrenForTheRight(child.children, newTreeMenuItem);
    });
  }

  private disableLeftItems(items: TreeMenuItem[]) {
    if (isNullOrUndefined(items)) {
      return;
    }
    items.forEach((it) => {
      if (it.selected && !it.disabled) {
        it.disabled = true;
      }
      this.disableLeftItems(it.children);
    });
  }

  private readonly moveRightToLeft = () => {
    let length = this.accumulatedItems.length;
    while (length > 0) {
      if (this.accumulatedItems[length - 1].selected) {
        const toBeRemovedItem = this.items.find((leftItem) => leftItem.uuid === this.accumulatedItems[length - 1].uuid);
        this.enableAndDeSelectOnTheLeft(toBeRemovedItem);
        this.accumulatedItems.splice((length - 1), 1);
      } else if (this.accumulatedItems[length - 1].indeterminate) {
        const toBeRemovedItem = this.items.find((leftItem) => leftItem.uuid === this.accumulatedItems[length - 1].uuid);
        this.findSelectedItemsToBeRemoved(this.accumulatedItems[length - 1], toBeRemovedItem);
      }
      length--;
    }
    this.accumulatedItems.forEach((item) => this.resetRemainingItemStates(item));
    this.accumulatedItems = cloneDeep(this.accumulatedItems);
    this.items = cloneDeep(this.items);
    this.rightContainer.unselectSelectAll().then(console.debug);
    this.accumulatedEvent.emit(removeCircularReplacer(this.accumulatedItems, true));
    this.removeButtonEnabled = false;
  };

  private findSelectedItemsToBeRemoved(item: TreeMenuItem, toBeRemovedLeftItem: TreeMenuItem) {

    if (!isNullOrUndefined(item.children)) {
      let length = item.children.length;
      while (length > 0) {
        const toBeRemovedLeftChild = toBeRemovedLeftItem.children.find((leftChild) => {
          return leftChild.uuid === item.children[length - 1].uuid;
        });
        if (item.children[length - 1].selected) {
          this.enableAndDeSelectOnTheLeft(toBeRemovedLeftChild);
          this.setParentStatusOfTheLeft(toBeRemovedLeftChild.parent);
          item.children.splice((length - 1), 1);
        } else {
          this.findSelectedItemsToBeRemoved(item.children[length - 1], toBeRemovedLeftChild);
        }
        length--;
      }
    }
  }

  private setParentStatusOfTheLeft(parent: TreeMenuItem) {
    if (isNullOrUndefined(parent)) {
      return;
    }
    const totalChildren = parent.children.length;
    const selectedChildren = parent.children.filter((child) => !child.disabled && child.selected).length;
    parent.selected = totalChildren === selectedChildren;
    parent.indeterminate = totalChildren !== selectedChildren;
    parent.disabled = false;
    this.setParentStatusOfTheLeft(parent.parent);
  }

  private resetRemainingItemStates(item: TreeMenuItem) {
    if (!isNullOrUndefined(item)) {
      item.selected = false;
      item.indeterminate = false;
      if (!isNullOrUndefined(item.children)) {
        item.children.forEach((child) => this.resetRemainingItemStates(child));
      }
    }
  }

  private updateItemStatus(item: TreeMenuItem) {
    if (!isNullOrUndefined(item.children)) {
      const totalCount = item.children.length;
      const selectedCount = item.children.filter((it) => it.selected).length;
      if (totalCount === selectedCount || selectedCount === 0) {
        item.selected = false;
        item.indeterminate = false;
      }
      item.children.forEach((it) => {
        this.updateItemStatus(it);
      });
    }
  }

  private enableAndDeSelectOnTheLeft(item: TreeMenuItem) {
    if (isNullOrUndefined(item)) {
      return;
    }
    if (isNullOrUndefined(item.children)) {
      if (item.selected || item.indeterminate) {
        item.selected = false;
        item.indeterminate = false;
        item.disabled = false;
      }
    } else {
      item.children.forEach((child) => {
        if (child.disabled || child.indeterminate) {
          this.enableAndDeSelectOnTheLeft(child);
        }
      });
    }
    if (!isNullOrUndefined(item.parent)) {
      const rootParent = findRootParent(item);
      this.updateItemStatus(rootParent);
      item.parent.children.forEach((child) => {
        if (child.uuid === item.uuid) {
          child.selected = item.selected;
          child.disabled = item.disabled;
          child.indeterminate = item.indeterminate;
        }
      });
    }
    item.disabled = false;
  }

  private setUp() {
    this.setInitialState(this.items, this.accumulatedItems);
  }

  private setInitialState(items: TreeMenuItem[], accumulatedItems: TreeMenuItem[]) {
    if (isNullOrUndefined(items) || isNullOrUndefined(accumulatedItems) || accumulatedItems.length === 0) {
      return;
    }
    items.forEach((item) => {
      const input = isNullOrUndefined(accumulatedItems)
        ? null
        : accumulatedItems
          .find((inputItem) => item.uuid === inputItem.uuid);

      if (!this.setInitialStateOfItem(item, input)) {
        const itemChildrenCount = isNullOrUndefined(item.children) ? undefined : item.children.length;
        const inputChildrenCount = isNullOrUndefined(input.children) ? undefined : input.children.length;
        this.setInitialStateBasedOnChildren(item, itemChildrenCount, inputChildrenCount);
        this.setInitialState(item.children, input.children);
      }
    });
  }

  private setInitialStateBasedOnChildren(item: TreeMenuItem, itemChildrenCount: number, inputChildrenCount: number) {
    if (!isNullOrUndefined(itemChildrenCount) && itemChildrenCount !== inputChildrenCount) {
      item.selected = false;
      item.disabled = false;
      item.indeterminate = true;
    }
  }

  private setInitialStateOfItem(item: TreeMenuItem, input: TreeMenuItem): boolean {
    let conditionMet = false;
    if (isNullOrUndefined(input)) {
      conditionMet = true;
      item.selected = false;
      item.disabled = false;
      item.indeterminate = false;
    } else if (isEqual(item, input)) {
      conditionMet = true;
      item.indeterminate = false;
      item.selected = true;
      item.disabled = true;
    }
    return conditionMet;
  }

  private getListWidth() {
    const listWidth = (this.width - 155) / 2;
    return listWidth < 262.5 ? 262.5 : listWidth;
  }

  private readonly setAddButtonStatus = (event) => {
    if (!isNullOrUndefined(event)) {
      const listContainerItems = event.detail as TreeMenuItem[] || event as TreeMenuItem[];
      const enabledItems = listContainerItems.filter((i) => !i.disabled);
      this.addButtonEnabled = false;
      this.setButtonSelectedStatus(enabledItems, 'addButton');
    }
  };

  private setButtonSelectedStatus(items: TreeMenuItem[], selectedButton: 'addButton' | 'removeButton') {
    if (isNullOrUndefined(items)) {
      return;
    }
    for (const item of items) {
      if (item.selected && !item.disabled) {
        selectedButton === 'addButton' ? this.addButtonEnabled = true : this.removeButtonEnabled = true;
        break;
      }
      if (!isNullOrUndefinedOrEmptyString(selectedButton)) {
        this.setButtonSelectedStatus(item.children, selectedButton);
      }
    }
  }

  private readonly setRemoveButtonStatus = (event) => {
    if (!isNullOrUndefined(event)) {
      const listContainerItems = event.detail as TreeMenuItem[] || event as TreeMenuItem[];
      this.removeButtonEnabled = false;
      this.setButtonSelectedStatus(listContainerItems, 'removeButton');
    }
  };

  private sourceItemOpen = (event: CustomEvent<TreeMenuItem>) => {
    this.sourceOpenEvent.emit(event.detail);
  };

  private sourceItemClose = (event: CustomEvent<TreeMenuItem>) => {
    this.sourceCloseEvent.emit(event.detail);
  };

  private destinationItemOpen = (event: CustomEvent<TreeMenuItem>) => {
    this.destinationOpenEvent.emit(removeCircularReplacer(event.detail));
  };

  private destinationItemClose = (event: CustomEvent<TreeMenuItem>) => {
    this.destinationCloseEvent.emit(removeCircularReplacer(event.detail));
  };

  render() {
    return (
      <Host>
        <div class='flex flex-no-wrap justify-center' style={{ minWidth: '600px' }}>
          <mx-pick-list-container
            ref={(ref) => this.leftContainer = ref}
            items={this.items}
            width={this.getListWidth()}
            height={this.height}
            label='Available'
            isCompact={this.isCompact}
            hideCount={this.hideCount}
            showChildCount={this.showChildCount}
            hideCaret={this.hideCaret}
            onListOpenEvent={this.sourceItemOpen}
            onListCloseEvent={this.sourceItemClose}
            onListContainerEvent={(event: CustomEvent<TreeMenuItem[]>) => this.setAddButtonStatus(event.detail)}
          ></mx-pick-list-container>

          <div class='self-center flex flex-col px-16 mt-48'>
            <kds-button
              aria-label='Add'
              kind='dominant'
              palette='brand'
              disabled={!this.addButtonEnabled}
              onClick={this.moveLeftToRight}>
              <kds-label class='pl-24'>Add</kds-label>
              <kds-icon-right-arrow></kds-icon-right-arrow>
            </kds-button>
            <div class='pb-16'></div>
            <kds-button
              kind='dominant'
              palette='brand'
              variant='border'
              aria-label='Remove'
              disabled={!this.removeButtonEnabled}
              onClick={this.moveRightToLeft}>
              <kds-icon-left-arrow></kds-icon-left-arrow>
              <kds-label>Remove</kds-label>
            </kds-button>
          </div>

          <mx-pick-list-container
            ref={(ref) => this.rightContainer = ref}
            items={this.accumulatedItems}
            width={this.getListWidth()}
            height={this.height}
            label='Picked'
            isCompact={this.isCompact}
            hideCount={this.hideCount}
            hideCaret={this.hideCaret}
            showChildCount={this.showChildCount}
            onListOpenEvent={this.destinationItemOpen}
            onListCloseEvent={this.destinationItemClose}
            onListContainerEvent={this.setRemoveButtonStatus}
          ></mx-pick-list-container>
        </div>

      </Host>
    );
  }
}
